const TileAsset_t* assets_tiles_resolve(TilesetTheme_t theme, LogicalTileId_t logical_tile)
{
    (void)theme;
    (void)logical_tile;
    return 0;
}

const TileAsset_t* assets_tiles_resolve_id(TilesetTheme_t theme, uint8_t tile_id)
{
    if (tile_id == 0u) {
        return 0;
    }

    switch (theme) {
    case TILESET_OVERWORLD:
        if (tile_id <= ASSETS_OVERWORLD_TILE_COUNT) {
            return &overworld_tile_assets[(uint8_t)(tile_id - 1u)];
        }
        break;
    case TILESET_SPEAKER:
        if (tile_id <= ASSETS_SPEAKER_TILE_COUNT) {
            return &speaker_tile_assets[(uint8_t)(tile_id - 1u)];
        }
        break;
    case TILESET_DISPLAY:
        if (tile_id <= ASSETS_DISPLAY_TILE_COUNT) {
            return &display_tile_assets[(uint8_t)(tile_id - 1u)];
        }
        break;
    default:
        break;
    }

    return 0;
}

uint8_t assets_tiles_count(TilesetTheme_t theme)
{
    switch (theme) {
    case TILESET_OVERWORLD:
        return ASSETS_OVERWORLD_TILE_COUNT;
    case TILESET_SPEAKER:
        return ASSETS_SPEAKER_TILE_COUNT;
    case TILESET_DISPLAY:
        return ASSETS_DISPLAY_TILE_COUNT;
    default:
        return 0u;
    }
}
